// @ts-check
//
// In-process Tac Worker host (ABI driver).
//
// Loads an in-house-compiled `tac.wasm` / `yon.wasm` and invokes its worker ABI
// (`call`, `alloc`, `output_ptr`, `output_len`) directly on the host runtime —
// no Web Worker, no subprocess. This is the server-side analogue of the browser
// worker runtime generated by `Compiler.createWorkerRuntimeSource`; the
// `wasm-compiled` execution backend uses it to serve `yon.[ext]` routes that
// Tachyon's own compiler can lower to wasm.
//
// Values follow the worker ABI (see src/compiler/wasm/*): a `call` lowers to a
// `{ status, headers, body: { method, result } }` JSON response written to
// output_ptr/output_len. Method and request envelope are passed as JSON; the
// envelope's `.body` is what the handler sees via `request.body()`.

const encoder = new TextEncoder();
const decoder = new TextDecoder();

/** @typedef {{ status: number, headers?: Record<string, string>, body?: any }} TacWorkerResponse */

export class TacWasmHost {
    /**
     * @param {WebAssembly.Exports} exports
     * @param {string} [label] Source label used in diagnostics.
     */
    constructor(exports, label = 'tac worker') {
        if (!(exports.memory instanceof WebAssembly.Memory))
            throw new Error(`Tac worker ${label} must export memory`);
        for (const name of ['alloc', 'call', 'output_ptr', 'output_len']) {
            if (typeof (/** @type {Record<string, unknown>} */ (exports)[name]) !== 'function')
                throw new Error(`Tac worker ${label} must export ${name}()`);
        }
        /** @type {any} */
        this.exports = exports;
        this.label = label;
    }

    /**
     * Instantiate a Tac worker module from its wasm bytes.
     * @param {BufferSource} wasmBytes
     * @param {string} [label]
     * @returns {Promise<TacWasmHost>}
     */
    static async instantiate(wasmBytes, label) {
        const { instance } = await WebAssembly.instantiate(wasmBytes, {});
        return new TacWasmHost(instance.exports, label);
    }

    /**
     * Synchronously instantiate (the worker modules are tiny). Used to warm a
     * handler at server startup so requests never pay compilation/instantiation.
     * @param {BufferSource} wasmBytes
     * @param {string} [label]
     * @returns {TacWasmHost}
     */
    static instantiateSync(wasmBytes, label) {
        const module = new WebAssembly.Module(wasmBytes);
        const instance = new WebAssembly.Instance(module, {});
        return new TacWasmHost(instance.exports, label);
    }

    /**
     * Fresh byte view of linear memory. Re-created on every access because
     * `alloc` may have grown (and therefore detached) the previous buffer.
     * @returns {Uint8Array}
     */
    view() {
        return new Uint8Array(this.exports.memory.buffer);
    }

    /**
     * Copy UTF-8 text into freshly-allocated linear memory.
     * @param {string} text
     * @returns {{ ptr: number, len: number }}
     */
    writeText(text) {
        const bytes = encoder.encode(String(text));
        const ptr = this.exports.alloc(bytes.length || 1);
        if (!ptr)
            throw new Error(`Tac worker ${this.label} failed to allocate ${bytes.length} bytes`);
        this.view().set(bytes, ptr);
        return { ptr, len: bytes.length };
    }

    /** @param {unknown} value @returns {{ ptr: number, len: number }} */
    writeJson(value) {
        return this.writeText(JSON.stringify(value ?? null));
    }

    /** @param {{ ptr: number, len: number } | null} input */
    dealloc(input) {
        if (input && typeof this.exports.dealloc === 'function')
            this.exports.dealloc(input.ptr, input.len);
    }

    /**
     * Read and JSON-parse the worker's output buffer.
     * @returns {any}
     */
    readOutput() {
        const ptr = this.exports.output_ptr();
        const len = this.exports.output_len();
        if (!len)
            return {};
        const text = decoder.decode(this.view().subarray(ptr, ptr + len));
        try {
            return JSON.parse(text);
        }
        catch {
            throw new Error(`Tac worker ${this.label} produced invalid JSON output: ${text.slice(0, 200)}`);
        }
    }

    /**
     * Invoke a handler method. `request` is the full request envelope the
     * handler sees via `request.json()`; its `.body` becomes `request.body()`.
     * @param {string} method HTTP verb, e.g. 'GET'.
     * @param {Record<string, unknown>} request
     * @returns {TacWorkerResponse}
     */
    call(method, request) {
        const rawBody = request && typeof request === 'object' ? request.body : undefined;
        const bodyText = typeof rawBody === 'string' ? rawBody : JSON.stringify(rawBody ?? null);
        const methodInput = this.writeJson(method);
        const requestInput = this.writeJson(request);
        const bodyInput = this.writeText(bodyText);
        try {
            this.exports.call(
                methodInput.ptr, methodInput.len,
                requestInput.ptr, requestInput.len,
                bodyInput.ptr, bodyInput.len,
            );
            return this.readOutput();
        }
        finally {
            this.dealloc(methodInput);
            this.dealloc(requestInput);
            this.dealloc(bodyInput);
        }
    }
}
